form:Form.form:Scripts:
		
function Refresh(CONTROL, LISTA)
{
	//Esta el Control
	if (Ctrl(LISTA+"_LIST")?false:true) return;

	//Leo los VALORES
	var t,c=0;
	var values=Ctrl(CONTROL).GetXValue();
	var xmlValues=new NomadXML("ROWS");
	var xmlValue;

	//Recorro los VALORES
	if (values!="")
	{
		values=values.split("|");

		for (t=0; t<values.length; t++)
		{       
			c++;
			xmlValue=xmlValues.AddTailElement("ROW");
			xmlValue.SetAttr("id", values[t]);
			xmlValue.SetAttr("values", values[t]);
		}
	}

	//Actualizo la LISTA
	Ctrl(LISTA+"_LIST").processResult(xmlValues.ToString());

	//Actualizo los Controles
	CtrlEnabled(LISTA+"_REM"         , (c==0?false:true));
	CtrlEnabled(LISTA+"_LIST_DEL"    , (c==0?false:true));
	CtrlEnabled(LISTA+"_LIST_DEL_ALL", (c==0?false:true));
}

function DelToList(CONTROL, LISTA, refreshControl)
{
	//Leo el VALOR
	var value=Ctrl(LISTA+"_LIST").GetXValue();
	if (value=="") return;

	var t;       
	var values=Ctrl(CONTROL).GetXValue();

	if (values!="")
	{
		//recorro para ver si existe el VALOR
		values=values.split("|");
		for (t=0; t<values.length; t++)
			if (values[t]==value) 
			{
				//Elimino el Valor
				values.splice(t,1);
				break;
			}

		//Actualizo el Campo
		Ctrl(CONTROL).SetXValue(values.join("|"));			
	}

	//Actualizo el Control
	if (refreshControl)
		Ctrl(LISTA+"_EDIT").SetXValue(value);

	//Actualizo la Lista
	Refresh(CONTROL, LISTA);
}         

function DelAllToList(CONTROL, LISTA, refreshControl)
{       
	//Limpio los VALORER
	Ctrl(CONTROL).SetXValue("");

	//Actualizo la Lista
	Refresh(CONTROL, LISTA);
}


function AddToList(CONTROL, LISTA, extVALUE)
{
	//Leo el VALOR
	var value=(extVALUE?extVALUE:Ctrl(LISTA+"_EDIT").GetXValue());
	if (value=="") return;

	var t;       
	var values=Ctrl(CONTROL).GetXValue();

	if (values!="")
	{
		//recorro para ver si existe el VALOR
		values=values.split("|");
		for (t=0; t<values.length; t++)
			if (values[t]==value) return;

		//Agrego el Valor
		values.push(value);

		//Reordeno la lista
		values=values.sort();

		//Actualizo el Campo
		Ctrl(CONTROL).SetXValue(values.join("|"));			
	} else
	{                  
		//Actualizo el Campo
		Ctrl(CONTROL).SetXValue(value);
	}

	//Actualizo la Lista
	Refresh(CONTROL, LISTA);
}



function HorasRem()    { DelToList("d_horas", "HORAS", true); }
function HorasAdd()    { AddToList("d_horas", "HORAS", null); }
function HorasDel()    { DelToList("d_horas", "HORAS", false); }
function HorasDelAll() { DelAllToList("d_horas", "HORAS"); }

function DiasSemanaRem()    { DelToList("d_dias_semana", "DIAS_SEMANA", true); }
function DiasSemanaAdd()    { AddToList("d_dias_semana", "DIAS_SEMANA", null); }
function DiasSemanaDel()    { DelToList("d_dias_semana", "DIAS_SEMANA", false); }
function DiasSemanaDelAll() { DelAllToList("d_dias_semana", "DIAS_SEMANA"); }

function SemanasMesRem()    { DelToList("d_semanas_mes", "SEMANAS_MES", true); }
function SemanasMesAdd()    { AddToList("d_semanas_mes", "SEMANAS_MES", null); }
function SemanasMesDel()    { DelToList("d_semanas_mes", "SEMANAS_MES", false); }
function SemanasMesDelAll() { DelAllToList("d_semanas_mes", "SEMANAS_MES"); }

function MesesRem()    { DelToList("d_meses", "MESES", true); }
function MesesAdd()    { AddToList("d_meses", "MESES", null); }
function MesesDel()    { DelToList("d_meses", "MESES", false); }
function MesesDelAll() { DelAllToList("d_meses", "MESES"); }

function DiasMesRem()    
{ 
	//Leo el VALOR
	var value=Ctrl("DIAS_MES_LIST").GetXValue();
	switch(value)
	{
		case "": return;

		case "UL": case "PE":  
			Ctrl("DIAS_MES_EDIT2").SetXValue(value);
			Ctrl("DIAS_MES_EDIT").SetXValue("");
			DelToList("d_dias_mes", "DIAS_MES", false); 
			break;

		default:                    
			Ctrl("DIAS_MES_EDIT2").SetXValue("DI");
			DelToList("d_dias_mes", "DIAS_MES", true); 
			break;

	}
}
function DiasMesAdd()    
{                           
	if (Ctrl("DIAS_MES_EDIT2").GetXValue()=="DI")
	{
		if(Ctrl("DIAS_MES_EDIT").TypedValue()< 1) return;
		if(Ctrl("DIAS_MES_EDIT").TypedValue()>31) return;
		AddToList("d_dias_mes", "DIAS_MES", (Ctrl("DIAS_MES_EDIT").TypedValue()+100).toString().substr(1)); 
	} else
	{     
		AddToList("d_dias_mes", "DIAS_MES", Ctrl("DIAS_MES_EDIT2").GetXValue()); 
	}
}
function DiasMesDel()    { DelToList("d_dias_mes", "DIAS_MES", false); }
function DiasMesDelAll() { DelAllToList("d_dias_mes", "DIAS_MES"); }
function DiasMesChangeDia() { Ctrl("DIAS_MES_EDIT2").SetXValue("DI"); }

function AnnosRem() { DelToList("d_annos", "ANNOS", true); }
function AnnosAdd()    
{                           
	if(Ctrl("ANNOS_EDIT").TypedValue()<2000) return;
	if(Ctrl("ANNOS_EDIT").TypedValue()>2100) return;
	AddToList("d_annos", "ANNOS", null); 
}
function AnnosDel()    { DelToList("d_annos", "ANNOS", false); }
function AnnosDelAll() { DelAllToList("d_annos", "ANNOS"); }

function OnLoadCustom()
{
	//Llamo al Onload del BASE
	OnLoad();

	//Actualizo los ListVIEW
	Refresh("d_horas", "HORAS");
	Refresh("d_dias_semana", "DIAS_SEMANA");
	Refresh("d_dias_mes", "DIAS_MES");
	Refresh("d_semanas_mes", "SEMANAS_MES");
	Refresh("d_meses", "MESES");
	Refresh("d_annos", "ANNOS"); 

	//Seteo por defecto los valores de los campos del Evento  
	if(Ctrl("main").GetMode() == "EDIT_E")
	{
		if(Ctrl("c_modo_evento").GetXValue() == "")
		{
			Ctrl("c_modo_evento").SetXValue("T");
			Ctrl("d_horas_e").SetXValue("0000"); 
		}
		else 
		{
			Ctrl("d_horas_e").SetXValue(Ctrl("d_horas").GetXValue());
		}

		//Guardo el valor del evento, cargo las opciones y se lo seteo
		evento = Ctrl("c_evento").GetXValue();
		cargaEventos();
		Ctrl("c_evento").SetXValue(evento);
	}     


}          

function Save()
{
	if(Ctrl("main").GetMode() == "EDIT_E")
	{
		Ctrl("d_horas").SetXValue(Ctrl("d_horas_e").GetXValue());
		return true;
	}            
	else return true;
}       

function cargaEventos()
{
	//Cargo los eventos filtrados por el grupo seleccionado
	var nSQL = GetProxy().SQLService();   
	var xml = nSQL.GetOBJ(Ctrl("main").getResource("qry_eventos"), "<PARAMS UUID=\""+Ctrl("c_grupo_evento").GetXValue()+"\" />");
	var xmlOptions = createDoc("" + xml.ToString());
	Ctrl("c_evento").setOptions(xmlOptions);
}
